-- DMT_V_PROJECTS_DETAIL
CREATE OR REPLACE FORCE EDITIONABLE VIEW "DMT_V_PROJECTS_DETAIL" ("RUN_STATUS", "ERROR_TEXT", "RECONCILIATION_STATUS", "PROJECT_NAME", "PROJECT_NUMBER", "SOURCE_TEMPLATE_NUMBER", "SOURCE_APPLICATION_CODE", "SOURCE_PROJECT_REFERENCE", "ORGANIZATION_NAME", "LEGAL_ENTITY_NAME", "DESCRIPTION", "PROJECT_MANAGER_NUMBER", "PROJECT_MANAGER_NAME", "PROJECT_MANAGER_EMAIL", "PROJECT_START_DATE", "PROJECT_FINISH_DATE", "CLOSED_DATE", "PROJECT_STATUS_NAME", "PROJECT_PRIORITY_CODE", "OUTLINE_DISPLAY_LEVEL", "PLANNING_PROJECT_FLAG", "SERVICE_TYPE_CODE", "WORK_TYPE_NAME", "LIMIT_TO_TXN_CONTROLS_CODE", "PROJECT_CURRENCY_CODE", "CURRENCY_CONV_RATE_TYPE", "CURRENCY_CONV_DATE_TYPE_CODE", "CURRENCY_CONV_DATE", "CINT_ELIGIBLE_FLAG", "CINT_RATE_SCH_NAME", "CINT_STOP_DATE", "ASSET_ALLOCATION_METHOD_CODE", "CAPITAL_EVENT_PROCESSING_CODE", "ALLOW_CROSS_CHARGE_FLAG", "CC_PROCESS_LABOR_FLAG", "LABOR_TP_SCHEDULE_NAME", "LABOR_TP_FIXED_DATE", "CC_PROCESS_NL_FLAG", "NL_TP_SCHEDULE_NAME", "NL_TP_FIXED_DATE", "BURDEN_SCHEDULE_NAME", "BURDEN_SCH_FIXED_DATED", "KPI_NOTIFICATION_ENABLED", "KPI_NOTIFICATION_RECIPIENTS", "KPI_NOTIFICATION_INCLUDE_NOTES", "COPY_TEAM_MEMBERS_FLAG", "COPY_PROJECT_CLASSES_FLAG", "COPY_ATTACHMENTS_FLAG", "COPY_DFF_FLAG", "COPY_GROUP_SPACE_FLAG", "COPY_TASKS_FLAG", "COPY_TASK_ATTACHMENTS_FLAG", "COPY_TASK_DFF_FLAG", "COPY_TASK_ASSIGNMENTS_FLAG", "COPY_TRANSACTION_CONTROLS_FLAG", "COPY_ASSETS_FLAG", "COPY_ASSET_ASSIGNMENTS_FLAG", "COPY_COST_OVERRIDES_FLAG", "ATTRIBUTE_CATEGORY", "ATTRIBUTE1", "ATTRIBUTE2", "ATTRIBUTE3", "ATTRIBUTE4", "ATTRIBUTE5", "ATTRIBUTE6", "ATTRIBUTE7", "ATTRIBUTE8", "ATTRIBUTE9", "ATTRIBUTE10", "ATTRIBUTE11", "ATTRIBUTE12", "ATTRIBUTE13", "ATTRIBUTE14", "ATTRIBUTE15", "ATTRIBUTE16", "ATTRIBUTE17", "ATTRIBUTE18", "ATTRIBUTE19", "ATTRIBUTE20", "ATTRIBUTE21", "ATTRIBUTE22", "ATTRIBUTE23", "ATTRIBUTE24", "ATTRIBUTE25", "ATTRIBUTE26", "ATTRIBUTE27", "ATTRIBUTE28", "ATTRIBUTE29", "ATTRIBUTE30", "ATTRIBUTE31", "ATTRIBUTE32", "ATTRIBUTE33", "ATTRIBUTE34", "ATTRIBUTE35", "ATTRIBUTE36", "ATTRIBUTE37", "ATTRIBUTE38", "ATTRIBUTE39", "ATTRIBUTE40", "ATTRIBUTE41", "ATTRIBUTE42", "ATTRIBUTE43", "ATTRIBUTE44", "ATTRIBUTE45", "ATTRIBUTE46", "ATTRIBUTE47", "ATTRIBUTE48", "ATTRIBUTE49", "ATTRIBUTE50", "ATTRIBUTE1_NUMBER", "ATTRIBUTE2_NUMBER", "ATTRIBUTE3_NUMBER", "ATTRIBUTE4_NUMBER", "ATTRIBUTE5_NUMBER", "ATTRIBUTE6_NUMBER", "ATTRIBUTE7_NUMBER", "ATTRIBUTE8_NUMBER", "ATTRIBUTE9_NUMBER", "ATTRIBUTE10_NUMBER", "ATTRIBUTE11_NUMBER", "ATTRIBUTE12_NUMBER", "ATTRIBUTE13_NUMBER", "ATTRIBUTE14_NUMBER", "ATTRIBUTE15_NUMBER", "ATTRIBUTE1_DATE", "ATTRIBUTE2_DATE", "ATTRIBUTE3_DATE", "ATTRIBUTE4_DATE", "ATTRIBUTE5_DATE", "ATTRIBUTE6_DATE", "ATTRIBUTE7_DATE", "ATTRIBUTE8_DATE", "ATTRIBUTE9_DATE", "ATTRIBUTE10_DATE", "ATTRIBUTE11_DATE", "ATTRIBUTE12_DATE", "ATTRIBUTE13_DATE", "ATTRIBUTE14_DATE", "ATTRIBUTE15_DATE", "SCHEDULE_NAME", "EPS_NAME", "PROJECT_PLAN_VIEW_ACCESS", "SCHEDULE_TYPE", "OPPORTUNITY_ID", "OPPORTUNITY_NUMBER", "OPPORTUNITY_CUSTOMER_NUMBER", "OPPORTUNITY_CUSTOMER_ID", "OPPORTUNITY_AMT", "OPPORTUNITY_CURRCODE", "OPPORTUNITY_WIN_CONF_PERCENT", "OPPORTUNITY_NAME", "OPPORTUNITY_DESC", "OPPORTUNITY_CUSTOMER_NAME", "OPPORTUNITY_STATUS", "PRJ_PLAN_BASELINE_NAME", "PRJ_PLAN_BASELINE_DESC", "PRJ_PLAN_BASELINE_DATE", "BUDGETARY_CONTROL_FLAG", "SOURCE_TEMPLATE_NAME", "CASCADE_OPTION", "SOURCE_ID", "STG_SEQUENCE_ID", "RUN_ID", "INTEGRATION_ID", "PREFIX", "SCENARIO_ID", "STAGE_DATE", "LAST_UPDATED_DATE")  AS 
  SELECT
    NVL(tfm.TFM_STATUS, stg.STG_STATUS)                             AS RUN_STATUS,
    tfm.ERROR_TEXT                                           AS ERROR_TEXT,
    CASE
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'LOADED' THEN 'CONFIRMED'
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NOT NULL THEN 'CONFIRMED'
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NULL THEN 'UNRECONCILED'
        ELSE 'IN_PROGRESS'
    END                                                      AS RECONCILIATION_STATUS,
    stg.PROJECT_NAME                                        AS PROJECT_NAME,
    stg.PROJECT_NUMBER                                      AS PROJECT_NUMBER,
    stg.SOURCE_TEMPLATE_NUMBER,
    stg.SOURCE_APPLICATION_CODE,
    stg.SOURCE_PROJECT_REFERENCE,
    stg.ORGANIZATION_NAME,
    stg.LEGAL_ENTITY_NAME,
    stg.DESCRIPTION,
    stg.PROJECT_MANAGER_NUMBER,
    stg.PROJECT_MANAGER_NAME,
    stg.PROJECT_MANAGER_EMAIL,
    stg.PROJECT_START_DATE,
    stg.PROJECT_FINISH_DATE,
    stg.CLOSED_DATE,
    stg.PROJECT_STATUS_NAME,
    stg.PROJECT_PRIORITY_CODE,
    stg.OUTLINE_DISPLAY_LEVEL,
    stg.PLANNING_PROJECT_FLAG,
    stg.SERVICE_TYPE_CODE,
    stg.WORK_TYPE_NAME,
    stg.LIMIT_TO_TXN_CONTROLS_CODE,
    stg.PROJECT_CURRENCY_CODE,
    stg.CURRENCY_CONV_RATE_TYPE,
    stg.CURRENCY_CONV_DATE_TYPE_CODE,
    stg.CURRENCY_CONV_DATE,
    stg.CINT_ELIGIBLE_FLAG,
    stg.CINT_RATE_SCH_NAME,
    stg.CINT_STOP_DATE,
    stg.ASSET_ALLOCATION_METHOD_CODE,
    stg.CAPITAL_EVENT_PROCESSING_CODE,
    stg.ALLOW_CROSS_CHARGE_FLAG,
    stg.CC_PROCESS_LABOR_FLAG,
    stg.LABOR_TP_SCHEDULE_NAME,
    stg.LABOR_TP_FIXED_DATE,
    stg.CC_PROCESS_NL_FLAG,
    stg.NL_TP_SCHEDULE_NAME,
    stg.NL_TP_FIXED_DATE,
    stg.BURDEN_SCHEDULE_NAME,
    stg.BURDEN_SCH_FIXED_DATED,
    stg.KPI_NOTIFICATION_ENABLED,
    stg.KPI_NOTIFICATION_RECIPIENTS,
    stg.KPI_NOTIFICATION_INCLUDE_NOTES,
    stg.COPY_TEAM_MEMBERS_FLAG,
    stg.COPY_PROJECT_CLASSES_FLAG,
    stg.COPY_ATTACHMENTS_FLAG,
    stg.COPY_DFF_FLAG,
    stg.COPY_GROUP_SPACE_FLAG,
    stg.COPY_TASKS_FLAG,
    stg.COPY_TASK_ATTACHMENTS_FLAG,
    stg.COPY_TASK_DFF_FLAG,
    stg.COPY_TASK_ASSIGNMENTS_FLAG,
    stg.COPY_TRANSACTION_CONTROLS_FLAG,
    stg.COPY_ASSETS_FLAG,
    stg.COPY_ASSET_ASSIGNMENTS_FLAG,
    stg.COPY_COST_OVERRIDES_FLAG,
    stg.ATTRIBUTE_CATEGORY,
    stg.ATTRIBUTE1,
    stg.ATTRIBUTE2,
    stg.ATTRIBUTE3,
    stg.ATTRIBUTE4,
    stg.ATTRIBUTE5,
    stg.ATTRIBUTE6,
    stg.ATTRIBUTE7,
    stg.ATTRIBUTE8,
    stg.ATTRIBUTE9,
    stg.ATTRIBUTE10,
    stg.ATTRIBUTE11,
    stg.ATTRIBUTE12,
    stg.ATTRIBUTE13,
    stg.ATTRIBUTE14,
    stg.ATTRIBUTE15,
    stg.ATTRIBUTE16,
    stg.ATTRIBUTE17,
    stg.ATTRIBUTE18,
    stg.ATTRIBUTE19,
    stg.ATTRIBUTE20,
    stg.ATTRIBUTE21,
    stg.ATTRIBUTE22,
    stg.ATTRIBUTE23,
    stg.ATTRIBUTE24,
    stg.ATTRIBUTE25,
    stg.ATTRIBUTE26,
    stg.ATTRIBUTE27,
    stg.ATTRIBUTE28,
    stg.ATTRIBUTE29,
    stg.ATTRIBUTE30,
    stg.ATTRIBUTE31,
    stg.ATTRIBUTE32,
    stg.ATTRIBUTE33,
    stg.ATTRIBUTE34,
    stg.ATTRIBUTE35,
    stg.ATTRIBUTE36,
    stg.ATTRIBUTE37,
    stg.ATTRIBUTE38,
    stg.ATTRIBUTE39,
    stg.ATTRIBUTE40,
    stg.ATTRIBUTE41,
    stg.ATTRIBUTE42,
    stg.ATTRIBUTE43,
    stg.ATTRIBUTE44,
    stg.ATTRIBUTE45,
    stg.ATTRIBUTE46,
    stg.ATTRIBUTE47,
    stg.ATTRIBUTE48,
    stg.ATTRIBUTE49,
    stg.ATTRIBUTE50,
    stg.ATTRIBUTE1_NUMBER,
    stg.ATTRIBUTE2_NUMBER,
    stg.ATTRIBUTE3_NUMBER,
    stg.ATTRIBUTE4_NUMBER,
    stg.ATTRIBUTE5_NUMBER,
    stg.ATTRIBUTE6_NUMBER,
    stg.ATTRIBUTE7_NUMBER,
    stg.ATTRIBUTE8_NUMBER,
    stg.ATTRIBUTE9_NUMBER,
    stg.ATTRIBUTE10_NUMBER,
    stg.ATTRIBUTE11_NUMBER,
    stg.ATTRIBUTE12_NUMBER,
    stg.ATTRIBUTE13_NUMBER,
    stg.ATTRIBUTE14_NUMBER,
    stg.ATTRIBUTE15_NUMBER,
    stg.ATTRIBUTE1_DATE,
    stg.ATTRIBUTE2_DATE,
    stg.ATTRIBUTE3_DATE,
    stg.ATTRIBUTE4_DATE,
    stg.ATTRIBUTE5_DATE,
    stg.ATTRIBUTE6_DATE,
    stg.ATTRIBUTE7_DATE,
    stg.ATTRIBUTE8_DATE,
    stg.ATTRIBUTE9_DATE,
    stg.ATTRIBUTE10_DATE,
    stg.ATTRIBUTE11_DATE,
    stg.ATTRIBUTE12_DATE,
    stg.ATTRIBUTE13_DATE,
    stg.ATTRIBUTE14_DATE,
    stg.ATTRIBUTE15_DATE,
    stg.SCHEDULE_NAME,
    stg.EPS_NAME,
    stg.PROJECT_PLAN_VIEW_ACCESS,
    stg.SCHEDULE_TYPE,
    stg.OPPORTUNITY_ID,
    stg.OPPORTUNITY_NUMBER,
    stg.OPPORTUNITY_CUSTOMER_NUMBER,
    stg.OPPORTUNITY_CUSTOMER_ID,
    stg.OPPORTUNITY_AMT,
    stg.OPPORTUNITY_CURRCODE,
    stg.OPPORTUNITY_WIN_CONF_PERCENT,
    stg.OPPORTUNITY_NAME,
    stg.OPPORTUNITY_DESC,
    stg.OPPORTUNITY_CUSTOMER_NAME,
    stg.OPPORTUNITY_STATUS,
    stg.PRJ_PLAN_BASELINE_NAME,
    stg.PRJ_PLAN_BASELINE_DESC,
    stg.PRJ_PLAN_BASELINE_DATE,
    stg.BUDGETARY_CONTROL_FLAG,
    stg.SOURCE_TEMPLATE_NAME,
    stg.CASCADE_OPTION,
    stg.SOURCE_ID,
    stg.STG_SEQUENCE_ID,
    tfm.RUN_ID,
    tfm.RUN_ID                                              AS INTEGRATION_ID,
    cm.PREFIX,
    CAST(NULL AS NUMBER)                                    AS SCENARIO_ID,
    stg.STAGE_DATE,
    NVL(tfm.LAST_UPDATED_DATE, stg.LAST_UPDATED_DATE)      AS LAST_UPDATED_DATE
FROM DMT_OWNER.DMT_PJF_PROJECTS_STG_TBL stg
LEFT JOIN (
    SELECT t.*,
           ROW_NUMBER() OVER (PARTITION BY t.STG_SEQUENCE_ID
                              ORDER BY t.TFM_SEQUENCE_ID DESC) AS rn
    FROM   DMT_OWNER.DMT_PJF_PROJECTS_TFM_TBL t
) tfm ON tfm.STG_SEQUENCE_ID = stg.STG_SEQUENCE_ID AND tfm.rn = 1
LEFT JOIN DMT_OWNER.DMT_PIPELINE_RUN_TBL cm
    ON cm.RUN_ID = tfm.RUN_ID;
